import { AppError } from "../shared/app-error";
import { Subscription } from "./subscription";
import { SubscriptionRepository } from "./subscription-repository";

const THIRTY_DAYS_MS = 2_592_000_000;

function generateId(): string {
  return Math.random().toString(36).slice(2) + Math.random().toString(36).slice(2);
}

export class SubscriptionService {
  constructor(private readonly repo: SubscriptionRepository) {}

  /**
   * Creates a new active subscription for the given user and plan.
   * AC1: status is "active"; renewalDate is now + 30 days.
   */
  createSubscription(userId: string, planId: string): Subscription {
    const now = Date.now();
    const subscription: Subscription = {
      id: generateId(),
      userId,
      planId,
      status: "active",
      createdAt: now,
      renewalDate: now + THIRTY_DAYS_MS,
    };
    this.repo.save(subscription);
    return subscription;
  }

  /**
   * Returns the subscription with the given ID.
   * AC2: returns subscription when found.
   * AC3: throws SUBSCRIPTION_NOT_FOUND when not found.
   */
  getSubscription(id: string): Subscription {
    const subscription = this.repo.findById(id);
    if (subscription === null) {
      throw new AppError("SUBSCRIPTION_NOT_FOUND", `Subscription "${id}" was not found.`);
    }
    return subscription;
  }

  /**
   * Cancels an active subscription.
   * AC4: sets status to "cancelled" and records cancellationDate.
   * AC5: throws SUBSCRIPTION_ALREADY_CANCELLED if already cancelled.
   */
  cancelSubscription(id: string): Subscription {
    const subscription = this.getSubscription(id);

    if (subscription.status === "cancelled") {
      throw new AppError(
        "SUBSCRIPTION_ALREADY_CANCELLED",
        `Subscription "${id}" is already cancelled.`
      );
    }

    const updated: Subscription = {
      ...subscription,
      status: "cancelled",
      cancellationDate: Date.now(),
    };
    this.repo.save(updated);
    return updated;
  }

  /**
   * Renews an active subscription by pushing renewalDate forward 30 days.
   * AC6: sets renewalDate to now + 30 days for active subscriptions.
   * AC7: throws CANNOT_RENEW_CANCELLED for cancelled subscriptions.
   */
  renewSubscription(id: string): Subscription {
    const subscription = this.getSubscription(id);

    if (subscription.status === "cancelled") {
      throw new AppError(
        "CANNOT_RENEW_CANCELLED",
        `Cannot renew subscription "${id}" because it is cancelled.`
      );
    }

    const updated: Subscription = {
      ...subscription,
      renewalDate: Date.now() + THIRTY_DAYS_MS,
    };
    this.repo.save(updated);
    return updated;
  }

  /**
   * Returns all subscriptions (active and cancelled) for the given user.
   * AC8: returns every subscription regardless of status.
   */
  listSubscriptions(userId: string): Subscription[] {
    return this.repo.findByUserId(userId);
  }
}

